    jest.useFakeTimers()
    jest.clearAllMocks()
  })

  afterEach(() => {
    flushPendingTimers()
    jest.useRealTimers()
  })

  const renderAndFlush = async (ui) => {
    let view
    await act(async () => {
      view = render(ui)
      await Promise.resolve()
    })
    return view
